import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from '@/components/ui/accordion';
import { toast } from 'sonner';
import {
  Shield,
  ShieldAlert,
  ShieldCheck,
  ShieldX,
  Play,
  Pause,
  RefreshCw,
  Download,
  Clock,
  AlertTriangle,
  CheckCircle,
  XCircle,
  Info,
  Bug,
  Lock,
  Unlock,
  Eye,
  EyeOff,
  Zap,
  Activity,
  Server,
  Database,
  Globe,
  Code,
  FileWarning,
  Loader2,
} from 'lucide-react';
