    auth: 'فعّل المصادقة الثنائية وحسّن سياسة كلمات المرور',
    session: 'استخدم tokens آمنة وحدد مدة صلاحية الجلسات',
    crypto: 'استخدم خوارزميات تشفير حديثة مثل AES-256',
