    session: ['ثغرة في إدارة الجلسات', 'Session Fixation', 'انتهاء صلاحية الجلسة'],
    crypto: ['تشفير ضعيف', 'مفاتيح مكشوفة', 'خوارزمية قديمة'],
    config: ['إعدادات غير آمنة', 'Debug Mode مفعل', 'Headers مفقودة'],
    data: ['تسريب بيانات', 'عدم تشفير البيانات', 'Backup مكشوف'],
    network: ['HTTPS غير مفعل', 'CORS غير آمن', 'منافذ مفتوحة'],
    files: ['رفع ملفات غير آمن', 'Path Traversal', 'ملفات حساسة مكشوفة'],
