    setIsScanning(true);
    const scanId = Date.now().toString();

    const newScan: ScanResult = {
      id: scanId,
      startedAt: new Date(),
      status: 'running',
      progress: 0,
      totalChecks: selectedCategories.length * 10,
      completedChecks: 0,
      vulnerabilities: [],
      summary: { critical: 0, high: 0, medium: 0, low: 0, info: 0, total: 0 },
    };

    setScanResult(newScan);

    // محاكاة تقدم الفحص
    const totalSteps = selectedCategories.length * 10;
