    config: ['إعدادات غير آمنة', 'Debug Mode مفعل', 'Headers مفقودة'],
    data: ['تسريب بيانات', 'عدم تشفير البيانات', 'Backup مكشوف'],
    network: ['HTTPS غير مفعل', 'CORS غير آمن', 'منافذ مفتوحة'],
